/**
 * rotation-correctness.ts -- Verify optimized functions produce correct results
 *
 * Compares optimized implementations against reference (naive) implementations
 * to ensure the rotations preserve correctness.
 */

import {
  createVoidBoundary,
  updateVoidBoundary,
  complementDistribution,
  decayVoidBoundary,
  giniCoefficient,
  shannonEntropy,
  excessKurtosis,
  measure,
  flattenStack,
  createBoundaryStack,
  createTimescaleBoundary,
  buleyeanWeight,
  teleportDeficit,
  mergeVoidBoundaries,
} from '../void';

let passed = 0;
let failed = 0;

function assert(condition: boolean, msg: string) {
  if (condition) {
    passed++;
  } else {
    failed++;
    console.error(`FAIL: ${msg}`);
  }
}

function assertClose(a: number, b: number, msg: string, tol = 1e-10) {
  if (Math.abs(a - b) < tol) {
    passed++;
  } else {
    failed++;
    console.error(
      `FAIL: ${msg} (got ${a}, expected ${b}, diff ${Math.abs(a - b)})`
    );
  }
}

// ============================================================================
// R1: Gini correctness -- compare O(N log N) against O(N²) reference
// ============================================================================

function giniReference(values: number[]): number {
  const sorted = [...values].sort((a, b) => a - b);
  const n = sorted.length;
  const mu = sorted.reduce((a, b) => a + b, 0) / n;
  if (mu === 0) return 0;
  let sumDiff = 0;
  for (let i = 0; i < n; i++)
    for (let j = 0; j < n; j++) sumDiff += Math.abs(sorted[i] - sorted[j]);
  return sumDiff / (2 * n * n * mu);
}

console.log('[R1] Gini correctness...');

// Test 1: Uniform values (Gini = 0)
assertClose(giniCoefficient([1, 1, 1, 1]), 0, 'uniform should be 0');

// Test 2: Maximum inequality
const maxIneq = [0, 0, 0, 100];
assertClose(
  giniCoefficient(maxIneq),
  giniReference(maxIneq),
  'max inequality match',
  1e-6
);

// Test 3: Random values match reference
for (let trial = 0; trial < 20; trial++) {
  const n = 8 + Math.floor(Math.random() * 50);
  const vals = Array.from({ length: n }, () => Math.random() * 100);
  const optimized = giniCoefficient(vals);
  const reference = giniReference(vals);
  assertClose(optimized, reference, `random trial ${trial} (n=${n})`, 1e-6);
}

// Test 4: Edge cases
assertClose(giniCoefficient([]), 0, 'empty');
assertClose(giniCoefficient([5]), 0, 'single');
assertClose(giniCoefficient([0, 0, 0]), 0, 'all zeros');

// ============================================================================
// R2: complementDistribution correctness
// ============================================================================

console.log('[R2] Complement distribution correctness...');

function complementReference(counts: number[], eta: number): number[] {
  const max = Math.max(...counts);
  const min = Math.min(...counts);
  const range = max - min;
  const norm =
    range > 0 ? counts.map((v) => (v - min) / range) : counts.map(() => 0);
  const weights = norm.map((v) => Math.exp(-eta * v));
  const sum = weights.reduce((a, b) => a + b, 0);
  return weights.map((w) => w / sum);
}

// Test: random boundaries
for (let trial = 0; trial < 10; trial++) {
  const dims = 4 + Math.floor(Math.random() * 30);
  const b = createVoidBoundary(dims);
  for (let i = 0; i < 50; i++) {
    updateVoidBoundary(b, Math.floor(Math.random() * dims));
  }
  const optimized = complementDistribution(b, 3.0);
  const reference = complementReference(b.counts, 3.0);
  for (let i = 0; i < dims; i++) {
    assertClose(
      optimized[i],
      reference[i],
      `complement trial ${trial} dim ${i}`,
      1e-12
    );
  }
  // Verify sums to 1
  const sum = optimized.reduce((a, b) => a + b, 0);
  assertClose(sum, 1.0, `complement sum trial ${trial}`, 1e-12);
}

// Test: uniform counts (all zeros)
const uniformB = createVoidBoundary(5);
const uniformDist = complementDistribution(uniformB, 3.0);
for (let i = 0; i < 5; i++) {
  assertClose(uniformDist[i], 0.2, `uniform dist dim ${i}`, 1e-12);
}

// ============================================================================
// R3: decayVoidBoundary correctness
// ============================================================================

console.log('[R3] Decay correctness...');

const decayB = createVoidBoundary(4);
updateVoidBoundary(decayB, 0, 10);
updateVoidBoundary(decayB, 1, 20);
updateVoidBoundary(decayB, 2, 30);
updateVoidBoundary(decayB, 3, 40);

decayVoidBoundary(decayB, 0.1);
assertClose(decayB.counts[0], 9, 'decay dim 0');
assertClose(decayB.counts[1], 18, 'decay dim 1');
assertClose(decayB.counts[2], 27, 'decay dim 2');
assertClose(decayB.counts[3], 36, 'decay dim 3');
assertClose(decayB.totalEntries, 90, 'decay totalEntries');

// ============================================================================
// R4: teleportDeficit correctness
// ============================================================================

console.log('[R4] Teleport deficit correctness...');

const tdB = createVoidBoundary(4);
updateVoidBoundary(tdB, 0, 5);
updateVoidBoundary(tdB, 1, 10);
updateVoidBoundary(tdB, 2, 3);
updateVoidBoundary(tdB, 3, 7);
// totalEntries = 25, minCount = 3, deficit = 25 - 3*4 = 13
assertClose(teleportDeficit(tdB), 13, 'teleportDeficit basic');

const tdEmpty = createVoidBoundary(0);
assertClose(teleportDeficit(tdEmpty), 0, 'teleportDeficit empty');

// ============================================================================
// R5: flattenStack correctness
// ============================================================================

console.log('[R5] FlattenStack correctness...');

const layer0 = createTimescaleBoundary('l0', 'seconds', 3);
updateVoidBoundary(layer0.boundary, 0, 5);
updateVoidBoundary(layer0.boundary, 1, 10);

const layer1 = createTimescaleBoundary('l1', 'minutes', 2);
updateVoidBoundary(layer1.boundary, 0, 3);
updateVoidBoundary(layer1.boundary, 1, 7);

const stack = createBoundaryStack('test', [layer0, layer1]);
const flat = flattenStack(stack);

assert(flat.counts.length === 5, 'flattenStack dims');
assertClose(flat.counts[0], 5, 'flattenStack [0]');
assertClose(flat.counts[1], 10, 'flattenStack [1]');
assertClose(flat.counts[2], 0, 'flattenStack [2]');
assertClose(flat.counts[3], 3, 'flattenStack [3]');
assertClose(flat.counts[4], 7, 'flattenStack [4]');
assertClose(flat.totalEntries, 25, 'flattenStack totalEntries');

// ============================================================================
// R6: measure fusion correctness (no double complement)
// ============================================================================

console.log('[R6] Measure fusion correctness...');

const mB = createVoidBoundary(8);
for (let i = 0; i < 100; i++) {
  updateVoidBoundary(mB, Math.floor(Math.random() * 8));
}
const m = measure(mB, 3.0, 50);
const dist = complementDistribution(mB, 3.0);
assertClose(m.entropy, shannonEntropy(dist), 'measure entropy');
assertClose(m.kurtosis, excessKurtosis(dist), 'measure kurtosis');
assertClose(m.gini, giniCoefficient(dist), 'measure gini');
const expectedIB = (Math.log(8) - shannonEntropy(dist)) / 50;
assertClose(m.inverseBule, expectedIB, 'measure inverseBule', 1e-12);

// ============================================================================
// mergeVoidBoundaries
// ============================================================================

console.log('[Merge] mergeVoidBoundaries...');

const mA = createVoidBoundary(3);
updateVoidBoundary(mA, 0, 5);
updateVoidBoundary(mA, 2, 10);

const mBB = createVoidBoundary(4);
updateVoidBoundary(mBB, 1, 3);
updateVoidBoundary(mBB, 3, 7);

const merged = mergeVoidBoundaries(mA, mBB);
assert(merged.counts.length === 4, 'merge dims');
assertClose(merged.counts[0], 5, 'merge [0]');
assertClose(merged.counts[1], 3, 'merge [1]');
assertClose(merged.counts[2], 10, 'merge [2]');
assertClose(merged.counts[3], 7, 'merge [3]');
assertClose(merged.totalEntries, 25, 'merge totalEntries');

// ============================================================================
// buleyeanWeight invariants (Law 1: positivity, the sliver)
// ============================================================================

console.log('[Law 1] Buleyean positivity...');

for (let T = 0; T <= 100; T++) {
  for (let v = 0; v <= T + 10; v++) {
    const w = buleyeanWeight(T, v);
    assert(w >= 1, `buleyeanWeight(${T}, ${v}) >= 1 (got ${w})`);
  }
}

// ============================================================================
// Summary
// ============================================================================

console.log(`\n${passed} passed, ${failed} failed`);
if (failed > 0) {
  process.exit(1);
} else {
  console.log('All rotation correctness checks passed.');
}
